import{_ as e,f as a,k as o,N as l}from"./plugin-vue_export-helper.e5331ba5.js";const _='{"title":"\uC11C\uBB38","description":"","frontmatter":{},"headers":[{"level":2,"title":"store\uC758 \uAE30\uBCF8\uAC12\uC744 \uC218\uC815\uD588\uC9C0\uB9CC \uC801\uC6A9\uB418\uC9C0 \uC54A\uB294 \uBB38\uC81C","slug":"store\uC758-\uAE30\uBCF8\uAC12\uC744-\uC218\uC815\uD588\uC9C0\uB9CC-\uC801\uC6A9\uB418\uC9C0-\uC54A\uB294-\uBB38\uC81C"},{"level":2,"title":"\uCF58\uC194 \uB77C\uC6B0\uD2B8 \uACBD\uACE0 \uBB38\uC81C","slug":"\uCF58\uC194-\uB77C\uC6B0\uD2B8-\uACBD\uACE0-\uBB38\uC81C"},{"level":2,"title":"\uB85C\uCEEC\uC5D0\uC11C \uCC98\uC74C \uC2E4\uD589\uD560 \uB54C \uB85C\uB529\uC774 \uB290\uB9BC","slug":"\uB85C\uCEEC\uC5D0\uC11C-\uCC98\uC74C-\uC2E4\uD589\uD560-\uB54C-\uB85C\uB529\uC774-\uB290\uB9BC"},{"level":2,"title":"\uB77C\uC6B0\uD2B8 \uC804\uD658 \uC2DC \uD398\uC774\uC9C0\uAC00 \uC0C8\uB85C\uACE0\uCE68\uB418\uB294 \uBB38\uC81C","slug":"\uB77C\uC6B0\uD2B8-\uC804\uD658-\uC2DC-\uD398\uC774\uC9C0\uAC00-\uC0C8\uB85C\uACE0\uCE68\uB418\uB294-\uBB38\uC81C"},{"level":2,"title":"\uC758\uC874\uC131 \uC124\uCE58 \uBB38\uC81C","slug":"\uC758\uC874\uC131-\uC124\uCE58-\uBB38\uC81C"},{"level":2,"title":"\uD328\uD0A4\uC9C0 \uD30C\uC77C\uC774 \uB108\uBB34 \uD07D\uB2C8\uB2E4","slug":"\uD328\uD0A4\uC9C0-\uD30C\uC77C\uC774-\uB108\uBB34-\uD07D\uB2C8\uB2E4"},{"level":2,"title":"\uBC30\uD3EC \uD6C4 \uC560\uD50C\uB9AC\uCF00\uC774\uC158 \uC2E4\uD589\uC774 \uB290\uB9B0 \uACBD\uC6B0","slug":"\uBC30\uD3EC-\uD6C4-\uC560\uD50C\uB9AC\uCF00\uC774\uC158-\uC2E4\uD589\uC774-\uB290\uB9B0-\uACBD\uC6B0"},{"level":2,"title":"\uBA54\uB274 \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5","slug":"\uBA54\uB274-\uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5"},{"level":2,"title":"\uCEF4\uD3EC\uB10C\uD2B8 \uC0AC\uC6A9 \uBB38\uC81C","slug":"\uCEF4\uD3EC\uB10C\uD2B8-\uC0AC\uC6A9-\uBB38\uC81C"},{"level":2,"title":"Editor \uCF54\uB4DC \uC624\uB958","slug":"editor-\uCF54\uB4DC-\uC624\uB958"},{"level":2,"title":"\uB77C\uC6B0\uD2B8\uB97C \uCD94\uAC00\uD55C \uD6C4, \uD398\uC774\uC9C0\uAC00 \uD45C\uC2DC\uB418\uC9C0 \uC54A\uB294 \uBB38\uC81C","slug":"\uB77C\uC6B0\uD2B8\uB97C-\uCD94\uAC00\uD55C-\uD6C4-\uD398\uC774\uC9C0\uAC00-\uD45C\uC2DC\uB418\uC9C0-\uC54A\uB294-\uBB38\uC81C"},{"level":2,"title":"\uC0C8\uB85C\uC6B4 Vue \uD30C\uC77C\uC744 \uCD94\uAC00\uD55C \uD6C4, \uD3B8\uC9D1\uAE30\uC5D0\uC11C \uD0C0\uC785 \uC624\uB958\uAC00 \uBC1C\uC0DD\uD568","slug":"\uC0C8\uB85C\uC6B4-vue-\uD30C\uC77C\uC744-\uCD94\uAC00\uD55C-\uD6C4-\uD3B8\uC9D1\uAE30\uC5D0\uC11C-\uD0C0\uC785-\uC624\uB958\uAC00-\uBC1C\uC0DD\uD568"},{"level":2,"title":"\uC624\uD504\uB77C\uC778 \uC544\uC774\uCF58\uC744 \uD65C\uC131\uD654\uD558\uB294 \uBC29\uBC95","slug":"\uC624\uD504\uB77C\uC778-\uC544\uC774\uCF58\uC744-\uD65C\uC131\uD654\uD558\uB294-\uBC29\uBC95"}],"relativePath":"guide/fqa.md","lastUpdated":1723014140914}',r={},t=l(`<h1 id="\uC11C\uBB38"><a class="header-anchor" href="#\uC11C\uBB38" aria-hidden="true">#</a> \uC11C\uBB38</h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>\uBA87 \uAC00\uC9C0 \uC77C\uBC18\uC801\uC778 \uBB38\uC81C\uB97C \uB098\uC5F4\uD588\uC2B5\uB2C8\uB2E4. \uBB38\uC81C\uAC00 \uC788\uC744 \uACBD\uC6B0 \uBA3C\uC800 \uC5EC\uAE30\uC5D0\uC11C \uCC3E\uC544\uBCF4\uC2DC\uACE0 \uAD00\uB828 \uB2F5\uBCC0\uC774 \uC788\uB294\uC9C0 \uD655\uC778\uD558\uC138\uC694.</p><p>\uB2F5\uBCC0\uC774 \uC5C6\uC73C\uBA74 <a href="https://github.com/web2-solution/web2-vue-framework/issues" target="_blank" rel="noopener noreferrer">issue</a> \uC5D0\uC11C \uC9C8\uBB38\uD558\uAC70\uB098 \uAC80\uC0C9\uD574 \uBCF4\uC138\uC694.</p></div><ul><li>\uAC1C\uBC1C\uC744 \uC9C4\uD589\uD560 \uB54C, \uBA3C\uC800 <a href="https://element-plus-admin-doc.cn/guide/introduction.html" target="_blank" rel="noopener noreferrer">\uD504\uB85C\uC81D\uD2B8 \uAC00\uC774\uB4DC</a>\uB97C \uC8FC\uC758 \uAE4A\uAC8C \uC77D\uC5B4\uBCF4\uC138\uC694. \uC804\uCCB4 \uBB38\uC11C\uB97C \uC0B4\uD3B4\uBCF4\uB294 \uAC83\uC774 \uC88B\uC2B5\uB2C8\uB2E4.</li><li>\uD504\uB808\uC784\uC6CC\uD06C \uC678\uC758 \uBB38\uC81C\uB294 Google\uC5D0\uC11C \uAC80\uC0C9\uD574 \uBCF4\uC138\uC694.</li><li>\uD574\uACB0\uC774 \uC5B4\uB835\uB2E4\uBA74, \uCEE4\uBBA4\uB2C8\uD2F0\uC5D0\uC11C \uC9C8\uBB38\uD558\uACE0 \uC11C\uB85C \uB17C\uC758\uD574 \uBCF4\uC138\uC694.</li><li>\uBB38\uC11C\uAC00 \uC624\uB798\uB418\uC5C8\uAC70\uB098 \uBD88\uBA85\uD655\uD55C \uBD80\uBD84\uC774 \uC788\uC73C\uBA74 issue\uB97C \uC81C\uAE30\uD558\uC5EC \uC810\uC9C4\uC801\uC73C\uB85C \uAC1C\uC120\uD574 \uB098\uAC00\uC138\uC694.</li></ul><h2 id="store\uC758-\uAE30\uBCF8\uAC12\uC744-\uC218\uC815\uD588\uC9C0\uB9CC-\uC801\uC6A9\uB418\uC9C0-\uC54A\uB294-\uBB38\uC81C"><a class="header-anchor" href="#store\uC758-\uAE30\uBCF8\uAC12\uC744-\uC218\uC815\uD588\uC9C0\uB9CC-\uC801\uC6A9\uB418\uC9C0-\uC54A\uB294-\uBB38\uC81C" aria-hidden="true">#</a> store\uC758 \uAE30\uBCF8\uAC12\uC744 \uC218\uC815\uD588\uC9C0\uB9CC \uC801\uC6A9\uB418\uC9C0 \uC54A\uB294 \uBB38\uC81C</h2><p>\uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C \uC77C\uBD80 Store\uAC00 \uAE30\uBCF8\uC801\uC73C\uB85C \uC9C0\uC18D\uD654(persistent) \uB418\uC5B4 \uC788\uAE30 \uB54C\uBB38\uC5D0, \uAE30\uBCF8\uAC12\uC744 \uC218\uC815\uD588\uB354\uB77C\uB3C4 \uCE90\uC2DC\uB41C \uAC12\uC774 \uC6B0\uC120\uC801\uC73C\uB85C \uC0AC\uC6A9\uB429\uB2C8\uB2E4. \uB530\uB77C\uC11C \uAE30\uBCF8\uAC12\uC744 \uC218\uC815\uD55C \uD6C4\uC5D0\uB294 \uBE0C\uB77C\uC6B0\uC800\uC758 <code>localStorage</code>\uB97C \uC218\uB3D9\uC73C\uB85C \uC0AD\uC81C\uD574 \uC8FC\uC138\uC694. \uADF8\uB7EC\uBA74 \uAE30\uBCF8\uAC12\uC774 \uC81C\uB300\uB85C \uC801\uC6A9\uB420 \uAC83\uC785\uB2C8\uB2E4.</p><h2 id="\uCF58\uC194-\uB77C\uC6B0\uD2B8-\uACBD\uACE0-\uBB38\uC81C"><a class="header-anchor" href="#\uCF58\uC194-\uB77C\uC6B0\uD2B8-\uACBD\uACE0-\uBB38\uC81C" aria-hidden="true">#</a> \uCF58\uC194 \uB77C\uC6B0\uD2B8 \uACBD\uACE0 \uBB38\uC81C</h2><p>\uB85C\uCEEC\uC5D0\uC11C \uC2E4\uD589\uD55C \uD6C4 \uB77C\uC6B0\uD2B8 \uACBD\uACE0\uAC00 \uB098\uD0C0\uB0A9\uB2C8\uB2E4.</p><div class="language-js"><pre><code><span class="token punctuation">[</span>Vue Router warn<span class="token punctuation">]</span><span class="token operator">:</span> No match found <span class="token keyword">for</span> location <span class="token keyword">with</span> path <span class="token string">&quot;/authorization/menu&quot;</span>
</code></pre></div><p>\uC774 \uBB38\uC81C\uB294 \uC2E0\uACBD \uC4F8 \uD544\uC694 \uC5C6\uC2B5\uB2C8\uB2E4. \uC774\uB294 vue-router\uC640 \uAD00\uB828\uB41C \uBB38\uC81C\uB85C, \uD504\uB85C\uC81D\uD2B8\uB97C \uBE4C\uB4DC\uD558\uC5EC \uBC30\uD3EC\uD55C \uD6C4\uC5D0\uB294 \uC774\uB7EC\uD55C \uACBD\uACE0\uAC00 \uB098\uD0C0\uB098\uC9C0 \uC54A\uC73C\uBBC0\uB85C, \uC774 \uBB38\uC81C\uB294 \uBB34\uC2DC\uD574\uB3C4 \uB429\uB2C8\uB2E4.</p><h2 id="\uB85C\uCEEC\uC5D0\uC11C-\uCC98\uC74C-\uC2E4\uD589\uD560-\uB54C-\uB85C\uB529\uC774-\uB290\uB9BC"><a class="header-anchor" href="#\uB85C\uCEEC\uC5D0\uC11C-\uCC98\uC74C-\uC2E4\uD589\uD560-\uB54C-\uB85C\uB529\uC774-\uB290\uB9BC" aria-hidden="true">#</a> \uB85C\uCEEC\uC5D0\uC11C \uCC98\uC74C \uC2E4\uD589\uD560 \uB54C \uB85C\uB529\uC774 \uB290\uB9BC</h2><p>\uB85C\uCEEC\uC5D0\uC11C \uC2E4\uD589\uD560 \uB54C\uB294 \uD544\uC694\uC5D0 \uB530\uB77C \uC5EC\uB7EC \uB9AC\uC18C\uC2A4\uB97C \uD55C \uBC88\uC5D0 \uB85C\uB4DC\uD558\uAE30 \uB54C\uBB38\uC5D0 \uCC98\uC74C\uC5D0\uB294 \uBE44\uAD50\uC801 \uB290\uB9B4 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uCE90\uC2DC\uAC00 \uC801\uC6A9\uB41C \uC774\uD6C4\uC5D0\uB294 \uCCAB \uB85C\uB529 \uC2DC\uAC04 \uBB38\uC81C\uB294 \uD574\uACB0\uB418\uC5B4, \uBE44\uC2B7\uD55C \uC791\uC5C5\uC744 \uBC18\uBCF5\uD560 \uB54C\uB294 \uAC70\uC758 \uC989\uC2DC \uC5F4\uB9AC\uAC8C \uB429\uB2C8\uB2E4.</p><p>Vite\uAC00 \uC5B4\uB5BB\uAC8C \uBE60\uB978\uC9C0\uC5D0 \uB300\uD574\uC11C\uB294 \uC9C1\uC811 Google\uC5D0\uC11C \uAC80\uC0C9\uD574 \uBCF4\uC138\uC694.</p><p>\uD604\uC7AC \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C\uB294 \uC2DC\uC791 \uC2DC\uAC04\uC744 \uCD5C\uC801\uD654\uD588\uC2B5\uB2C8\uB2E4. \uB85C\uCEEC\uC5D0\uC11C\uB294 \uAE30\uBCF8\uC801\uC73C\uB85C \uBAA8\uB4E0 <code>element-plus</code> \uC2A4\uD0C0\uC77C \uD30C\uC77C\uC744 \uB85C\uB4DC\uD558\uB3C4\uB85D \uC124\uC815\uD558\uC5EC, \uC694\uCCAD\uD558\uB294 \uB9AC\uC18C\uC2A4\uC758 \uC218\uB97C \uC904\uC600\uC2B5\uB2C8\uB2E4</p><p>\uC2DC\uC791 \uC18D\uB3C4\uB294 \uD604\uC7AC \uD30C\uC77C\uC5D0\uC11C \uCC38\uC870\uD558\uB294 \uB9AC\uC18C\uC2A4\uC758 \uC218\uC5D0 \uB530\uB77C \uACB0\uC815\uB429\uB2C8\uB2E4.</p><h2 id="\uB77C\uC6B0\uD2B8-\uC804\uD658-\uC2DC-\uD398\uC774\uC9C0\uAC00-\uC0C8\uB85C\uACE0\uCE68\uB418\uB294-\uBB38\uC81C"><a class="header-anchor" href="#\uB77C\uC6B0\uD2B8-\uC804\uD658-\uC2DC-\uD398\uC774\uC9C0\uAC00-\uC0C8\uB85C\uACE0\uCE68\uB418\uB294-\uBB38\uC81C" aria-hidden="true">#</a> \uB77C\uC6B0\uD2B8 \uC804\uD658 \uC2DC \uD398\uC774\uC9C0\uAC00 \uC0C8\uB85C\uACE0\uCE68\uB418\uB294 \uBB38\uC81C</h2><p>\uC774 \uBB38\uC81C\uB294 \uD574\uB2F9 \uB77C\uC6B0\uD2B8\uC5D0\uC11C \uC0AC\uC6A9\uD55C \uC81C3\uC790 \uBAA8\uB4C8\uC774 \uBBF8\uB9AC \uB85C\uB4DC\uB418\uC9C0 \uC54A\uC544\uC11C \uBC1C\uC0DD\uD569\uB2C8\uB2E4. \uC774 \uBAA8\uB4C8\uC744 \uB2E4\uC2DC \uB85C\uB4DC\uD574\uC57C \uD558\uBA70, \uC774\uB85C \uC778\uD574 <code>page reload</code>\uAC00 \uBC1C\uC0DD\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB85C \uC778\uD574 \uAC1C\uBC1C \uC911 \uBD88\uD3B8\uD568\uC774 \uCEE4\uC9C8 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uB530\uB77C\uC11C <code>vite.config.ts</code>\uC5D0\uC11C \uC0AC\uC804 \uB85C\uB4DC \uBAA9\uB85D\uC778 <code>optimizeDeps.include</code>\uB97C \uAD6C\uC131\uD558\uC5EC \uC11C\uBE44\uC2A4 \uC2DC\uC791 \uC2DC \uC774\uB7EC\uD55C \uBAA8\uB4C8\uC744 \uBBF8\uB9AC \uB85C\uB4DC\uD558\uACE0 \uD328\uD0A4\uC9D5\uD558\uB3C4\uB85D \uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4</p><h2 id="\uC758\uC874\uC131-\uC124\uCE58-\uBB38\uC81C"><a class="header-anchor" href="#\uC758\uC874\uC131-\uC124\uCE58-\uBB38\uC81C" aria-hidden="true">#</a> \uC758\uC874\uC131 \uC124\uCE58 \uBB38\uC81C</h2><ul><li>\uC758\uC874\uC131 \uC124\uCE58\uAC00 \uB418\uC9C0 \uC54A\uAC70\uB098 \uC2DC\uC791 \uC2DC \uC624\uB958\uAC00 \uBC1C\uC0DD\uD558\uB294 \uACBD\uC6B0, \uBA3C\uC800 <code>pnpm-lock</code> \uD30C\uC77C\uACFC <code>node_modules</code> \uD3F4\uB354\uB97C \uC0AD\uC81C\uD55C \uD6C4 <code>pnpm i</code> \uBA85\uB839\uC5B4\uB97C \uB2E4\uC2DC \uC2E4\uD589\uD574 \uBCF4\uC138\uC694.</li><li>\uAD6D\uB0B4 \uBBF8\uB7EC\uB97C \uC0AC\uC6A9\uD558\uC5EC \uC124\uCE58\uB97C \uC2DC\uB3C4\uD574 \uBCF4\uC138\uC694.</li><li>\uD504\uB85C\uC81D\uD2B8 \uACBD\uB85C\uC5D0 \uD55C\uAE00, \uC77C\uBCF8\uC5B4, \uC911\uAD6D\uC5B4 \uB4F1\uC758 \uD2B9\uC218 \uBB38\uC790\uB098 \uACF5\uBC31\uC774 \uC5C6\uB294\uC9C0 \uD655\uC778\uD558\uC138\uC694.</li><li>Node.js \uBC84\uC804\uC774 18 \uC774\uC0C1\uC778\uC9C0 \uD655\uC778\uD558\uC138\uC694.</li><li>\uD328\uD0A4\uC9C0 \uAD00\uB9AC\uC790\uB85C pnpm\uC744 \uC0AC\uC6A9\uD558\uACE0 \uC788\uB294\uC9C0 \uD655\uC778\uD558\uC138\uC694.</li></ul><h2 id="\uD328\uD0A4\uC9C0-\uD30C\uC77C\uC774-\uB108\uBB34-\uD07D\uB2C8\uB2E4"><a class="header-anchor" href="#\uD328\uD0A4\uC9C0-\uD30C\uC77C\uC774-\uB108\uBB34-\uD07D\uB2C8\uB2E4" aria-hidden="true">#</a> \uD328\uD0A4\uC9C0 \uD30C\uC77C\uC774 \uB108\uBB34 \uD07D\uB2C8\uB2E4</h2><p>\uC804\uCCB4 \uBC84\uC804\uC5D0\uC11C\uB294 \uB9CE\uC740 \uC81C3\uC790 \uBAA8\uB4C8\uC744 \uD3EC\uD568\uD558\uACE0 \uC788\uAE30 \uB54C\uBB38\uC5D0 \uD328\uD0A4\uC9C0 \uD30C\uC77C \uD06C\uAE30\uAC00 \uC0C1\uB300\uC801\uC73C\uB85C \uD074 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uD544\uC694\uD558\uC9C0 \uC54A\uC740 \uC81C3\uC790 \uBAA8\uB4C8\uC744 \uC81C\uAC70\uD558\uAC70\uB098, \uB354 \uAC00\uBCBC\uC6B4 \uBC84\uC804\uC744 \uC0AC\uC6A9\uD558\uC5EC \uAC1C\uBC1C\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.</p><p>\uD569\uB9AC\uC801\uC73C\uB85C \uCF54\uB4DC \uBD84\uD560\uC744 \uC218\uD589\uD558\uBA70, \uD604\uC7AC \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C\uB294 \uC77C\uBD80 \uD070 \uC81C3\uC790 \uBAA8\uB4C8\uC5D0 \uB300\uD574 \uCF54\uB4DC \uBD84\uD560\uC744 \uC801\uC6A9\uD558\uC600\uC2B5\uB2C8\uB2E4</p><h2 id="\uBC30\uD3EC-\uD6C4-\uC560\uD50C\uB9AC\uCF00\uC774\uC158-\uC2E4\uD589\uC774-\uB290\uB9B0-\uACBD\uC6B0"><a class="header-anchor" href="#\uBC30\uD3EC-\uD6C4-\uC560\uD50C\uB9AC\uCF00\uC774\uC158-\uC2E4\uD589\uC774-\uB290\uB9B0-\uACBD\uC6B0" aria-hidden="true">#</a> \uBC30\uD3EC \uD6C4 \uC560\uD50C\uB9AC\uCF00\uC774\uC158 \uC2E4\uD589\uC774 \uB290\uB9B0 \uACBD\uC6B0</h2><ul><li>\uD328\uD0A4\uC9C0 \uD30C\uC77C \uD06C\uAE30\uAC00 \uC801\uC808\uD55C\uC9C0 \uD655\uC778\uD558\uC138\uC694.</li><li>\uB124\uD2B8\uC6CC\uD06C\uAC00 \uC815\uC0C1\uC801\uC73C\uB85C \uC791\uB3D9\uD558\uB294\uC9C0 \uD655\uC778\uD558\uC138\uC694.</li><li>CDN \uCE90\uC2DC\uB97C \uD65C\uC131\uD654\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.</li><li>HTTP2\uB97C \uD65C\uC131\uD654\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.</li><li>Gzip \uC555\uCD95\uC744 \uD65C\uC131\uD654\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.</li></ul><h2 id="\uBA54\uB274-\uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5"><a class="header-anchor" href="#\uBA54\uB274-\uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5" aria-hidden="true">#</a> \uBA54\uB274 \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5</h2><p>\uBA54\uB274\uB294 \uB77C\uC6B0\uD2B8 \uC124\uC815\uC5D0 \uB530\uB77C \uC0DD\uC131\uB429\uB2C8\uB2E4. \uAE30\uC874 \uB77C\uC6B0\uD2B8 \uC124\uC815\uC774 \uC694\uAD6C\uC0AC\uD56D\uC744 \uCDA9\uC871\uD558\uB294\uC9C0 \uBA3C\uC800 \uD655\uC778\uD558\uC138\uC694. \uB9CC\uC57D \uCDA9\uC871\uD558\uC9C0 \uC54A\uB294\uB2E4\uBA74, \uC9C1\uC811 \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5 \uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.<a href="https://element-plus-admin-doc.cn/guide/router.html" target="_blank" rel="noopener noreferrer">\uB77C\uC6B0\uD2B8 \uAD00\uB828 \uBB38\uC11C</a>\uB97C \uCC38\uACE0\uD574 \uBCF4\uC138\uC694.</p><h2 id="\uCEF4\uD3EC\uB10C\uD2B8-\uC0AC\uC6A9-\uBB38\uC81C"><a class="header-anchor" href="#\uCEF4\uD3EC\uB10C\uD2B8-\uC0AC\uC6A9-\uBB38\uC81C" aria-hidden="true">#</a> \uCEF4\uD3EC\uB10C\uD2B8 \uC0AC\uC6A9 \uBB38\uC81C</h2><p>\uCEF4\uD3EC\uB10C\uD2B8\uB97C \uC0AC\uC6A9\uD560 \uB54C \uBB38\uC81C\uAC00 \uBC1C\uC0DD\uD558\uBA74, \uBA3C\uC800 \uD574\uB2F9 \uC628\uB77C\uC778 \uC608\uC81C\uB97C \uD655\uC778\uD558\uC5EC \uBB38\uC81C\uC640 \uAD00\uB828\uB41C \uCF54\uB4DC\uAC00 \uC788\uB294\uC9C0 \uC0B4\uD3B4\uBCF4\uC138\uC694. \uC608\uC81C\uB294 \uB300\uCCB4\uB85C <code>95%</code>\uC758 \uC0AC\uC6A9 \uBC29\uC2DD\uC744 \uCEE4\uBC84\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uB294 \uD574\uB2F9 \uCEF4\uD3EC\uB10C\uD2B8\uC758 \uBB38\uC11C\uB97C \uCC38\uC870\uD558\uC5EC \uBB38\uC81C\uB97C \uD574\uACB0\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.</p><h2 id="editor-\uCF54\uB4DC-\uC624\uB958"><a class="header-anchor" href="#editor-\uCF54\uB4DC-\uC624\uB958" aria-hidden="true">#</a> Editor \uCF54\uB4DC \uC624\uB958</h2><p>\uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C \uB300\uBD80\uBD84 <code>tsx</code>\uB97C \uC0AC\uC6A9\uD558\uBBC0\uB85C, \uAE30\uC874\uC758 <code>template</code> \uCF54\uB4DC \uADDC\uCE59\uC774 \uC801\uC6A9\uB418\uC9C0 \uC54A\uC744 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4, <code>v-if</code> \uB300\uC2E0 <code>{\uC870\uAC74 ? \uCC38 : \uAC70\uC9D3}</code>\uC744 \uC0AC\uC6A9\uD558\uC5EC \uD45C\uC2DC \uC5EC\uBD80\uB97C \uC81C\uC5B4\uD574\uC57C \uD569\uB2C8\uB2E4. \uAD00\uB828 \uBB38\uC11C\uB97C \uCC38\uACE0\uD558\uC138\uC694.</p><p>\uADF8\uB9AC\uACE0 <code>tsx</code> \uBB38\uBC95\uC744 \uC0AC\uC6A9\uD558\uB824\uBA74 <code>script</code>\uC5D0 <code>lang=&quot;tsx&quot;</code>\uAC00 \uC120\uC5B8\uB418\uC5B4 \uC788\uB294\uC9C0 \uD655\uC778\uD558\uC138\uC694.</p><h2 id="\uB77C\uC6B0\uD2B8\uB97C-\uCD94\uAC00\uD55C-\uD6C4-\uD398\uC774\uC9C0\uAC00-\uD45C\uC2DC\uB418\uC9C0-\uC54A\uB294-\uBB38\uC81C"><a class="header-anchor" href="#\uB77C\uC6B0\uD2B8\uB97C-\uCD94\uAC00\uD55C-\uD6C4-\uD398\uC774\uC9C0\uAC00-\uD45C\uC2DC\uB418\uC9C0-\uC54A\uB294-\uBB38\uC81C" aria-hidden="true">#</a> \uB77C\uC6B0\uD2B8\uB97C \uCD94\uAC00\uD55C \uD6C4, \uD398\uC774\uC9C0\uAC00 \uD45C\uC2DC\uB418\uC9C0 \uC54A\uB294 \uBB38\uC81C</h2><p>\uD504\uB85C\uC81D\uD2B8\uC5D0 \uC9C1\uC811 \uC815\uC801 \uB77C\uC6B0\uD2B8\uB97C \uCD94\uAC00\uD558\uB294 \uACBD\uC6B0, appStore\uC5D0\uC11C <code>dynamicRouter</code>\uC640 <code>serverDynamicRouter</code>\uAC00 <code>false</code>\uB85C \uC124\uC815\uB418\uC5B4 \uC788\uB294\uC9C0 \uD655\uC778\uD558\uACE0, \uBE0C\uB77C\uC6B0\uC800\uC758 <code>localStorage</code>\uB97C \uC218\uB3D9\uC73C\uB85C \uC9C0\uC6B0\uC138\uC694.</p><h2 id="\uC0C8\uB85C\uC6B4-vue-\uD30C\uC77C\uC744-\uCD94\uAC00\uD55C-\uD6C4-\uD3B8\uC9D1\uAE30\uC5D0\uC11C-\uD0C0\uC785-\uC624\uB958\uAC00-\uBC1C\uC0DD\uD568"><a class="header-anchor" href="#\uC0C8\uB85C\uC6B4-vue-\uD30C\uC77C\uC744-\uCD94\uAC00\uD55C-\uD6C4-\uD3B8\uC9D1\uAE30\uC5D0\uC11C-\uD0C0\uC785-\uC624\uB958\uAC00-\uBC1C\uC0DD\uD568" aria-hidden="true">#</a> \uC0C8\uB85C\uC6B4 Vue \uD30C\uC77C\uC744 \uCD94\uAC00\uD55C \uD6C4, \uD3B8\uC9D1\uAE30\uC5D0\uC11C \uD0C0\uC785 \uC624\uB958\uAC00 \uBC1C\uC0DD\uD568</h2><p>\uC774 \uBB38\uC81C\uB294 <code>Volar</code> \uD50C\uB7EC\uADF8\uC778\uACFC \uAD00\uB828\uB41C \uBB38\uC81C\uC785\uB2C8\uB2E4. \uC77C\uBC18\uC801\uC73C\uB85C \uC5D0\uB514\uD130\uB97C \uC7AC\uC2DC\uC791\uD558\uBA74 \uD574\uACB0\uB429\uB2C8\uB2E4.</p><h2 id="\uC624\uD504\uB77C\uC778-\uC544\uC774\uCF58\uC744-\uD65C\uC131\uD654\uD558\uB294-\uBC29\uBC95"><a class="header-anchor" href="#\uC624\uD504\uB77C\uC778-\uC544\uC774\uCF58\uC744-\uD65C\uC131\uD654\uD558\uB294-\uBC29\uBC95" aria-hidden="true">#</a> \uC624\uD504\uB77C\uC778 \uC544\uC774\uCF58\uC744 \uD65C\uC131\uD654\uD558\uB294 \uBC29\uBC95</h2><p>VITE_USE_ONLINE_ICON=false\uB85C \uC124\uC815\uD558\uBA74 \uC77C\uBD80 \uBC84\uC804\uC5D0\uC11C\uB294 \uC124\uC815\uC774 \uBB34\uD6A8\uD654\uB420 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB294 \uBC84\uADF8 \uB54C\uBB38\uC785\uB2C8\uB2E4.</p><p>\uCD5C\uC2E0 \uBC84\uC804\uC758 <code>uno.config.ts</code>\uC640 <code>Icon.vue</code> \uCF54\uB4DC\uB97C \uBCF5\uC0AC\uD558\uC5EC \uC0AC\uC6A9\uD574 \uBCF4\uC138\uC694.</p>`,37),d=[t];function i(s,c,n,h,p,u){return o(),a("div",null,d)}var g=e(r,[["render",i]]);export{_ as __pageData,g as default};
